import 'package:flutter/material.dart';
class SectionTitle extends StatelessWidget {  final String title;  final String subtitle;  const SectionTitle({    super.key,    required this.title,    required this.subtitle,  });  @override  Widget build(BuildContext context) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text(title, style: const TextStyle(fontSize: 34, fontWeight: FontWeight.w800)),        const SizedBox(height: 10),        Text(subtitle, style: const TextStyle(height: 1.6)),      ],    );  }}